class LockManager {
    /**
     * Initializes the LockManager with the specified lock file name.
     *
     * @param {string} fileName - The name of the lock file.
     */
    constructor(fileName) {
        /**
         * The full path to the lock file.
         * @type {string}
         * @private
         */
        this.lockFilePath = path.join(__dirname, fileName);

        /**
         * Indicates whether the lock has been acquired.
         * @type {boolean}
         * @private
         */
        this.lockAcquired = false;

